// Função para gerar hash SHA256 (simplificado)
function generateHash(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    const char = str.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  return Math.abs(hash).toString(16);
}

// Função para converter data DD/MM/YYYY para YYYY-MM-DD
function convertDateBrToIso(dateStr) {
  if (!dateStr || dateStr === '') return null;
  const parts = dateStr.split('/');
  if (parts.length === 3) {
    return `${parts[2]}-${parts[1].padStart(2, '0')}-${parts[0].padStart(2, '0')}`;
  }
  return null;
}

// Processa cada dependente
const processedDependents = dependentes.map(dependent => {
  const nomeDependente = dependent.nome_dependente || '';

  if (!nomeDependente || nomeDependente.trim() === '') {
    return null; // Pula dependentes sem nome
  }

  // Gera dependents_id usando o padrão: hash(id_funcionario + nome_dependente)
  const dependentIdString = `${employeeData.id_funcionario}-${nomeDependente}`;
  const dependentId = generateHash(dependentIdString);

  return {
    dependents_id: dependentId,
    id_funcionario: employeeData.id_funcionario,
    nome_funcionario: employeeData.nome_funcionario,
    nome_dependente: nomeDependente,
    tipo_dependente: dependent.tipo_dependente || '',
    fone_dependente: dependent.fone_dependente || '',
    rg: dependent.rg || '',
    cpf: dependent.cpf || '',
    data_nascimento: convertDateBrToIso(dependent.data_nascimento_dependente)
  };
}).filter(d => d !== null); // Remove dependentes inválidos

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'employers_plus_info',
  event: 'dependents_processed',
  id_funcionario: employeeData.id_funcionario,
  dependents_count: processedDependents.length,
  dependent_names: processedDependents.map(d => d.nome_dependente),
  level: 'info'
}));

return processedDependents.length > 0 ? processedDependents : [{ noDependents: true, employeeData }];

