// Função para decodificar entidades HTML
function decodeHtml(str) {
  if (!str || typeof str !== 'string') return str;
  return str
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&nbsp;/g, ' ')
    .replace(/&iacute;/g, 'í')
    .replace(/&ecirc;/g, 'ê')
    .replace(/&ccedil;/g, 'ç')
    .replace(/&otilde;/g, 'õ')
    .replace(/&aacute;/g, 'á')
    .replace(/&atilde;/g, 'ã')
    .replace(/&eacute;/g, 'é')
    .replace(/&oacute;/g, 'ó')
    .replace(/&uacute;/g, 'ú')
    .replace(/&acirc;/g, 'â')
    .replace(/&ocirc;/g, 'ô')
    .replace(/&ucirc;/g, 'û')
    .replace(/&Aacute;/g, 'Á')
    .replace(/&Eacute;/g, 'É')
    .replace(/&Iacute;/g, 'Í')
    .replace(/&Oacute;/g, 'Ó')
    .replace(/&Uacute;/g, 'Ú')
    .replace(/&Acirc;/g, 'Â')
    .replace(/&Ecirc;/g, 'Ê')
    .replace(/&Icirc;/g, 'Î')
    .replace(/&Ocirc;/g, 'Ô')
    .replace(/&Ucirc;/g, 'Û')
    .replace(/&Atilde;/g, 'Ã')
    .replace(/&Otilde;/g, 'Õ')
    .replace(/&Ccedil;/g, 'Ç');
}

// Parse XML simples para extrair dados dos comandos
function parseVhsysXml(xmlString) {
  const cmdRegex = /<cmd[^>]*\s+t=["']([^"']*)["'][^>]*>([\s\S]*?)<\/cmd>/gi;
  const data = {};
  let match;

  while ((match = cmdRegex.exec(xmlString)) !== null) {
    const fieldName = match[1];
    let fieldValue = match[2];

    // Remove CDATA se presente
    fieldValue = fieldValue.replace(/<!\[CDATA\[([\s\S]*?)\]\]>/gi, '$1');

    // Decode HTML entities
    fieldValue = decodeHtml(fieldValue.trim());

    data[fieldName] = fieldValue;
  }

  return data;
}

// Transforma dados separando benefícios e dependentes
function transformUserData(data) {
  const globalData = {};
  const dependentes = {};
  const beneficios = {};

  for (const [key, value] of Object.entries(data)) {
    // Verifica se é um campo numerado (dependente_1, beneficio_2, etc.)
    const match = key.match(/_([0-9]+)$/);

    if (match) {
      const number = match[1];
      const baseKey = key.replace(/_[0-9]+$/, '');

      if (key.includes('dependente') || key.includes('dependent')) {
        if (!dependentes[number]) dependentes[number] = {};
        dependentes[number][baseKey] = value;
      } else if (key.includes('beneficio') || key.includes('benefit')) {
        if (!beneficios[number]) beneficios[number] = {};
        beneficios[number][baseKey] = value;
      }
    } else {
      // Dados globais do funcionário
      globalData[key] = value;
    }
  }

  return {
    globalData,
    dependentes: Object.values(dependentes),
    beneficios: Object.values(beneficios)
  };
}

// Processa o XML
